import csv

def smart_title(name):
    words = (name or '').strip().lower().split()
    keep_lower = {'and', 'of', 'for', 'the', 'at', 'in', 'on', 'to', 'a'}
    return ' '.join(w if i > 0 and w in keep_lower else w.capitalize() for i, w in enumerate(words))

with open('datagov/2006-2007-school-progress-report/files/rows.txt', 'r', encoding='utf-8', newline='') as f:
    rows = list(csv.DictReader(f))

scored = []
for r in rows:
    level = (r.get('SCHOOL LEVEL*') or '').strip()
    raw = (r.get('SCHOOL') or '').strip().replace(" at Water's Edge", '')
    if raw.endswith(', The'):
        continue
    school = smart_title(raw)
    try:
        score = float((r.get('OVERALL SCORE') or '').strip())
    except (TypeError, ValueError):
        continue
    if level == 'High School' and school:
        scored.append((school, score))

top7 = sorted(scored, key=lambda x: (-x[1], x[0]))[:7]
result = [s for s, _ in top7]

